// Safely get the AI response
let rawResponse = $input.item.json;

// Handle different possible formats
let aiText = '';

if (typeof rawResponse === 'string') {
  aiText = rawResponse;
} else if (typeof rawResponse === 'object' && rawResponse !== null) {
  // Try common AI output fields
  aiText = rawResponse.response ||
           rawResponse.text ||
           rawResponse.content ||
           rawResponse.output ||
           rawResponse.message ||
           JSON.stringify(rawResponse); // fallback
} else {
  aiText = 'Sorry, I received an unexpected response.';
}

// Clean and ensure it's a non-empty string
aiText = String(aiText).trim();
if (!aiText || aiText === 'null' || aiText === '{}') {
  aiText = 'Hmm... I couldn’t generate a proper response. Please try again.';
}

// RETURN A CLEAN JSON OBJECT
return {
  json: {
    reply: aiText
  }
};
